var e=[{id:`L2_1`,type:`dialog`,speaker:`CAT_YAKSHA_NULL_NULL`,text:{KOREA:`소방관에게는 구해야할 목숨이 두 개가 있다고 하지. 하나는 구조자의 목숨. 그리고 다른 하나는 나 자신의 목숨.`,JPN:`消防士には救わなければならない命が二つあるんだ。一つは救助者の命。そしてもう一つは自分の命。`,ENG:`It is said that firefighters have two lives to save. One is the life of the person in danger, and the other is the life of themselves.`,TWN:`一名消防員要拯救兩條性命。一是求救者的命，另一條則是自己的。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CAT_YAKSHA_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`CAT_YAKSHA_NULL_NULL`,text:{KOREA:`하핫, 그러니까 너무 걱정하지 말라고. 보란 듯이 모두를 구해내고… 반드시 살아서 돌아올 테니까.`,JPN:`ははっ、だからあまり心配するな。皆を救い出し……意気揚々と必ず帰ってくるから。`,ENG:`Hah hah, so don't worry. I'll save everyone and make it back alive... I promise.`,TWN:`哈哈，所以不用太擔心。我會拯救所有人……然後活著回來。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CAT_YAKSHA_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}}];export{e as default};